// Emparejar banco-acumulativo v3 (POR PARENT FOLDER - 100% deterministico)
// Cada archivo lleva su parentId (id de subcarpeta). Mapea Valles<->Valles, Credil<->Credil.
const FOLDER_VALLES_DESC = '1KZt98PYd9V6w_zfSpl-fOl6F1v56Vb4t';
const FOLDER_CREDIL_DESC = '12jatMOkDTNHzIwwPZOlHnWc33uoqcxwM';
const FOLDER_VALLES_ACUM = '17Ut-5dL7ci9RZZhX72iD8qejZZdKnNkh';
const FOLDER_CREDIL_ACUM = '177YEDw4l3-RD7Vg7rG9-ApGyey7Kh3tn';

const dedupById = (arr) => {
  const seen = new Set();
  return arr.filter(x => seen.has(x.id) ? false : (seen.add(x.id), true));
};
const descargados = dedupById($('Split descargados').all().map(i => i.json));
const acumulativos = dedupById($('Split acumulativos').all().map(i => i.json));

function bancoDelArchivo(f, isDesc) {
  const parents = f.parents || [];
  if (isDesc) {
    if (parents.includes(FOLDER_VALLES_DESC)) return 'Valles';
    if (parents.includes(FOLDER_CREDIL_DESC)) return 'Credil';
  } else {
    if (parents.includes(FOLDER_VALLES_ACUM)) return 'Valles';
    if (parents.includes(FOLDER_CREDIL_ACUM)) return 'Credil';
  }
  return null;
}

// Validar: cada subcarpeta debe tener EXACTAMENTE 1 archivo
const descPorBanco = { Valles: [], Credil: [] };
for (const d of descargados) {
  const b = bancoDelArchivo(d, true);
  if (b) descPorBanco[b].push(d);
}
const acumPorBanco = { Valles: [], Credil: [] };
for (const a of acumulativos) {
  const b = bancoDelArchivo(a, false);
  if (b) acumPorBanco[b].push(a);
}

// Reglas: minimo 1 archivo por subcarpeta (descargado) y maximo 1
const bancos = ['Valles', 'Credil'];
const pares = [];
const warnings = [];

for (const banco of bancos) {
  const descs = descPorBanco[banco];
  const acums = acumPorBanco[banco];
  if (descs.length === 0) {
    throw new Error(`[CARPETA_${banco.toUpperCase()}_VACIA] No hay archivo de resumen del dia en la subcarpeta de ${banco}. ACCION: subir el archivo Resumen Movimientos del banco ${banco} a la subcarpeta correspondiente.`);
  }
  if (descs.length > 1) {
    throw new Error(`[CARPETA_${banco.toUpperCase()}_DUPLICADA] Hay ${descs.length} archivos en la subcarpeta de ${banco}. Debe haber solo 1 (el del dia actual). ACCION: borrar o mover los archivos viejos.`);
  }
  if (acums.length === 0) {
    throw new Error(`[ACUM_${banco.toUpperCase()}_VACIO] No hay archivo acumulativo del mes para ${banco}. ACCION: subir el archivo Bancos Coop del banco ${banco} a la subcarpeta correspondiente.`);
  }
  if (acums.length > 1) {
    throw new Error(`[ACUM_${banco.toUpperCase()}_DUPLICADO] Hay ${acums.length} acumulativos en la subcarpeta de ${banco}. Debe haber solo 1.`);
  }
  pares.push({
    descargado: descs[0],
    acumulativo: acums[0],
    banco: banco,
  });
}

if (pares.length === 0) {
  throw new Error('No se pudo emparejar ningun banco. Revisar que los archivos esten en sus subcarpetas.');
}

return pares.map(p => ({ json: {
  desc_id: p.descargado.id,
  desc_name: p.descargado.name,
  acum_id: p.acumulativo.id,
  acum_name: p.acumulativo.name,
  banco: p.banco,
}}));

// === VALIDACION_ROBUSTA_XLSX v2 ===
function _validarXLSX(buf, nombreArchivo) {
  const nombre = nombreArchivo || 'archivo';
  if (!buf || buf.length === 0) {
    throw new Error(`[XLSX_VACIO] El archivo "${nombre}" llego vacio (0 bytes). Re-subir al Drive correctamente.`);
  }
  if (buf.length < 500) {
    throw new Error(`[XLSX_PEQUENO] El archivo "${nombre}" es demasiado pequeno (${buf.length} bytes). Un xlsx valido tiene minimo ~5KB. Re-subir al Drive.`);
  }
  // Magic bytes iniciales: zip empieza con PK\x03\x04 (50 4B 03 04)
  const b0 = buf[0], b1 = buf[1], b2 = buf[2], b3 = buf[3];
  const esZip = b0 === 0x50 && b1 === 0x4B && (b2 === 0x03 || b2 === 0x05) && (b3 === 0x04 || b3 === 0x06);
  if (!esZip) {
    const hex = [b0,b1,b2,b3].map(b => (b||0).toString(16).padStart(2,'0')).join(' ');
    let pista = '';
    if (b0 === 0xD0 && b1 === 0xCF) pista = ' (archivo .xls antiguo, no .xlsx)';
    else if (b0 === 0x3C) pista = ' (HTML/XML)';
    else if (b0 === 0x7B) pista = ' (JSON)';
    else if (b0 === 0xEF && b1 === 0xBB) pista = ' (texto con BOM UTF-8)';
    throw new Error(`[XLSX_FORMATO_INCORRECTO] El archivo "${nombre}" NO es un xlsx. Bytes iniciales: ${hex}${pista}. ACCION: re-subir al Drive como .xlsx.`);
  }
  // End of Central Directory marker (PK\x05\x06 = 50 4B 05 06) en los ultimos ~22-65kb del zip
  // Buscar hacia atras desde el final
  const maxSearch = Math.min(buf.length, 65557); // EOCD puede estar precedido por hasta 64K de comentario
  let eocdEncontrado = false;
  for (let i = buf.length - 22; i >= Math.max(0, buf.length - maxSearch); i--) {
    if (buf[i] === 0x50 && buf[i+1] === 0x4B && buf[i+2] === 0x05 && buf[i+3] === 0x06) {
      eocdEncontrado = true;
      break;
    }
  }
  if (!eocdEncontrado) {
    throw new Error(`[XLSX_TRUNCADO] El archivo "${nombre}" (${buf.length} bytes) es un zip pero esta TRUNCADO o CORRUPTO (falta el marcador End-of-Central-Directory). Causa probable: el archivo se subio al Drive incompleto o se daño en la descarga. ACCION: re-subir el archivo al Drive desde el sistema fuente.`);
  }
}

async function _cargarXLSXSeguro(wb, buf, nombreArchivo) {
  try {
    await wb.xlsx.load(buf);
  } catch (e) {
    const msg = String(e?.message || e);
    if (msg.includes('central directory') || msg.includes('Corrupted zip') || msg.includes('invalid signature')) {
      throw new Error(`[XLSX_CORRUPTO] El archivo "${nombreArchivo}" no se pudo abrir (${msg.slice(0, 100)}). Causa: zip corrupto. ACCION: re-subir el archivo al Drive.`);
    }
    throw e;
  }
}
// === FIN VALIDACION ===

// Parse XLSX descargado con exceljs.
// Lee TODAS las filas (descargado completo, sin separadora). Output: 1 item con {data: [filas]}.
const ExcelJS = require('exceljs');

const item = $input.first();
if (!item || !item.binary || !item.binary.data) {
  throw new Error('Sin binary data del descargado');
}
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'banco_dia'));

const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('No hay worksheet en el descargado');

const rowCount = ws.rowCount || 0;
// VALIDACION_VACIOS — Bloque hardening:
if (rowCount < 2) {
  throw new Error(`Archivo vacio o solo headers en pestana '${ws.name || 'desconocida'}' (rowCount=${rowCount}). Verifica que el XLSX tenga datos.`);
}

if (rowCount < 1) return [{ json: { data: [] } }];

// Leer headers (fila 1)
const headerRow = ws.getRow(1);
const headers = [];
const colCount = ws.columnCount || 1;
for (let c = 1; c <= colCount; c++) {
  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}
// BLINDAJE 2026-05-29: si el encabezado de 'valor' quedo en blanco (defecto del export
// del banco), inferirlo. En los extractos, 'valor' va inmediatamente antes de 'saldo'.
function _normH(s){ return String(s||'').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
const _tieneValor = headers.some(h => { const n=_normH(h); return n==='valor' || n==='monto'; });
if (!_tieneValor) {
  const _idxSaldo = headers.findIndex(h => _normH(h) === 'saldo');
  if (_idxSaldo > 0 && (!headers[_idxSaldo-1] || String(headers[_idxSaldo-1]).trim() === '')) {
    headers[_idxSaldo-1] = 'valor';
  }
}

// Leer filas 2..N como objetos {header: value}
const data = [];
for (let r = 2; r <= rowCount; r++) {
  const row = ws.getRow(r);
  const obj = {};
  let allEmpty = true;
  for (let c = 1; c <= colCount; c++) {
    const h = headers[c - 1];
    if (!h) continue;
    let v = row.getCell(c).value;
    // exceljs devuelve {result, formula} para celdas con formula — extraer result
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 10);
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  }
  if (!allEmpty) data.push(obj);
}

return [{ json: { data, headers, rowCount: data.length } }];

