// Aggregate acumulativo (fix formato): leer solo headers y meta,
// preservar binary para que Write pueda reusar el archivo original
const ExcelJS = require('exceljs');

const item = $input.first();
if (!item || !item.binary || !item.binary.data) {
  throw new Error('Sin binary data del acumulativo');
}
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'banco_acumulativo'));

const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('No hay worksheet en acumulativo');

const rowCount = ws.rowCount || 0;
if (rowCount < 2) {
  throw new Error(`Archivo vacio o solo headers (rowCount=${rowCount}).`);
}

