    headers[_idxSaldo-1] = 'valor';
  }
}

// Para identificar el doc de corte (lo necesita Merge), tomamos las primeras N filas
// (todas las "nuevas" hasta la separadora salmon o hasta 100 filas)
const data = [];
let separadoraEncontrada = false;
let separadoraRowIdx = -1;
for (let r = 2; r <= rowCount; r++) {
  const row = ws.getRow(r);
  const obj = {};
  let allEmpty = true;
  for (let c = 1; c <= colCount; c++) {
    const h = headers[c - 1];
    if (!h) continue;
    let v = row.getCell(c).value;
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 10);
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  }
  if (allEmpty && !separadoraEncontrada) {
    separadoraEncontrada = true;
    separadoraRowIdx = r;
    obj.__SEPARADORA__ = true;
    data.push(obj);
  } else if (!allEmpty) {
    data.push(obj);
  }
}

// FIX FORMATO: pasamos binary adelante para que Write reuse el archivo
return [{
  json: {
    data,
    headers,
    rowCount: data.length,
    hasSeparadora: separadoraEncontrada,
    separadoraRowIdx,
  },
  binary: item.binary
}];

// Merge banco logic v3 (FIX BUG FECHAS + MATCH ROBUSTO por doc+fecha+valor+secuencia)
function norm(s) {
  return String(s || '').trim().toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '');
}

function findKey(obj, ...candidates) {
  const keys = Object.keys(obj || {});
  for (const c of candidates) {
    const target = norm(c);
    if (!target) continue;  // ignorar candidatos vacios
    const f = keys.find(k => norm(k) === target);
    if (f) return f;
  }
  for (const c of candidates) {
    const target = norm(c);
    if (!target) continue;  // FIX: nunca hacer includes('') que matchea todo
    const f = keys.find(k => norm(k).includes(target));
    if (f) return f;
  }
  return null;
}

function normValor(v) {
  if (v === null || v === undefined || v === '') return '';
  const s = String(v).replace(/[^0-9.\-]/g, '');
  if (s === '') return '';
  return Math.round(parseFloat(s) * 100);  // centavos
}

const descRows = $('Aggregate descargado').first().json.data || [];
const acumData = $('Aggregate acumulativo').first().json;
const acumRows = acumData.data || [];

if (acumRows.length === 0) throw new Error('Acumulativo vacio');
if (descRows.length === 0) throw new Error('Descargado vacio');

// === DICCIONARIO DE FORMATOS (2026-05-31) ===
// Sinonimos de columnas de banco. Si el banco RENOMBRA una columna, agregar el nuevo
// nombre a la lista correspondiente AQUI (un solo lugar). El match exacto va primero,
// asi que los archivos actuales no cambian de comportamiento.
const SINONIMOS = {
  documento: ['documento', 'doc', 'numero documento', 'nro documento', 'comprobante', 'referencia'],
  fecha:     ['fecha', 'dia'],
  valor:     ['valor', 'monto', 'importe', 'credito', 'abono', 'haber', 'deposito'],
};
// === FIN DICCIONARIO ===
const acumKeyDoc = findKey(acumRows[0], ...SINONIMOS.documento);
const acumKeyFecha = findKey(acumRows[0], ...SINONIMOS.fecha);
const acumKeyValor = findKey(acumRows[0], ...SINONIMOS.valor);
const descKeyDoc = findKey(descRows[0], ...SINONIMOS.documento);
const descKeyFecha = findKey(descRows[0], ...SINONIMOS.fecha);
const descKeyValor = findKey(descRows[0], ...SINONIMOS.valor);

if (!acumKeyDoc || !acumKeyFecha) throw new Error('[HEADERS_ACUM] No se encontraron columnas Documento/Fecha en el acumulativo');
if (!descKeyDoc || !descKeyFecha) throw new Error('[HEADERS_DESC] No se encontraron columnas Documento/Fecha en el descargado');
if (!acumKeyValor) throw new Error('[HEADERS_ACUM] Falta columna Valor/Monto en el acumulativo');
if (!descKeyValor) throw new Error('[HEADERS_DESC] Falta columna Valor/Monto en el descargado');

// El "corte" = primera fila del acumulativo (la mas reciente registrada)
const ultimaFila = acumRows[0];
const docCorte = String(ultimaFila[acumKeyDoc] || '').trim();
const fechaCorte = String(ultimaFila[acumKeyFecha] || '').trim();
const valorCorte = normValor(ultimaFila[acumKeyValor]);

// Buscar match por (doc + fecha + valor) con verificacion de secuencia de 3 filas siguientes
let matchIdx = -1;
const candidatos = [];
for (let i = 0; i < descRows.length; i++) {
  const r = descRows[i];
  const docR = String(r[descKeyDoc] || '').trim();
  const fechaR = String(r[descKeyFecha] || '').trim();
  const valorR = normValor(r[descKeyValor]);
  if (docR === docCorte && fechaR === fechaCorte && valorR === valorCorte) {
    candidatos.push(i);
    // Verificar secuencia: las siguientes 3 filas deben coincidir tambien
    let seqOK = true;
    let seqVerificadas = 0;
    for (let k = 1; k <= 3; k++) {
      const acumK = acumRows[k];
      const descK = descRows[i + k];
      if (!acumK || !descK) break;  // sin mas filas, aceptamos
      const dA = String(acumK[acumKeyDoc] || '').trim();
      const fA = String(acumK[acumKeyFecha] || '').trim();
      const vA = normValor(acumK[acumKeyValor]);
      const dD = String(descK[descKeyDoc] || '').trim();
      const fD = String(descK[descKeyFecha] || '').trim();
      const vD = normValor(descK[descKeyValor]);
      if (dA !== dD || fA !== fD || vA !== vD) {
        seqOK = false;
        break;
      }
      seqVerificadas++;
    }
    if (seqOK) { matchIdx = i; break; }
  }
}

if (matchIdx === -1) {
  if (candidatos.length === 0) {
    throw new Error('[CORTE_NO_ENCONTRADO] El corte del acumulativo (doc=' + docCorte + ', fecha=' + fechaCorte + ', valor=' + valorCorte + ') no aparece en el archivo descargado. POSIBLES CAUSAS: (1) El archivo descargado es de otro periodo, (2) datos del banco corrompidos. ACCION: revisar que los archivos sean del mismo periodo y banco.');
  } else {
    throw new Error('[SECUENCIA_INVALIDA] Se encontro el corte ' + candidatos.length + ' vez(es) en el descargado pero ninguna coincidencia paso la verificacion de secuencia (3 filas siguientes no coinciden). POSIBLES CAUSAS: archivo descargado con datos faltantes/duplicados, o desfase entre archivos. ACCION: revisar manualmente antes de re-procesar.');
  }
}

// Filas nuevas = las que estan ARRIBA del match
const filasNuevasDesc = descRows.slice(0, matchIdx);

// FIX BUG FECHAS: filtrar headers vacios antes de mapear
const acumHeadersRaw = acumData.headers || Object.keys(acumRows[0] || {}).filter(k => k !== '__SEPARADORA__');
const acumHeaders = acumHeadersRaw.filter(h => h && String(h).trim() !== '');

const filasNuevasMapeadas = filasNuevasDesc.map(rDesc => {
  const out = {};
  for (const h of acumHeaders) {
    const dKey = findKey(rDesc, h);
    out[h] = dKey ? rDesc[dKey] : '';
  }
  return out;
});

return [{
  json: {
    filas_nuevas: filasNuevasMapeadas,
    headers: acumHeaders,
    total_nuevas: filasNuevasMapeadas.length,
    match_idx: matchIdx,
    candidatos_evaluados: candidatos.length,
    corte_doc: docCorte,
    corte_fecha: fechaCorte,
    corte_valor: valorCorte,
  },
  binary: $('Aggregate acumulativo').first().binary
}];

