    let pista = '';
    if (b0 === 0xD0 && b1 === 0xCF) pista = ' (archivo .xls antiguo, no .xlsx)';
    else if (b0 === 0x3C) pista = ' (HTML/XML)';
    else if (b0 === 0x7B) pista = ' (JSON)';
    else if (b0 === 0xEF && b1 === 0xBB) pista = ' (texto con BOM UTF-8)';
    throw new Error(`[XLSX_FORMATO_INCORRECTO] El archivo "${nombre}" NO es un xlsx. Bytes iniciales: ${hex}${pista}. ACCION: re-subir al Drive como .xlsx.`);
  }
  // End of Central Directory marker (PK\x05\x06 = 50 4B 05 06) en los ultimos ~22-65kb del zip
  // Buscar hacia atras desde el final
  const maxSearch = Math.min(buf.length, 65557); // EOCD puede estar precedido por hasta 64K de comentario
  let eocdEncontrado = false;
  for (let i = buf.length - 22; i >= Math.max(0, buf.length - maxSearch); i--) {
    if (buf[i] === 0x50 && buf[i+1] === 0x4B && buf[i+2] === 0x05 && buf[i+3] === 0x06) {
      eocdEncontrado = true;
      break;
    }
  }
  if (!eocdEncontrado) {
    throw new Error(`[XLSX_TRUNCADO] El archivo "${nombre}" (${buf.length} bytes) es un zip pero esta TRUNCADO o CORRUPTO (falta el marcador End-of-Central-Directory). Causa probable: el archivo se subio al Drive incompleto o se daño en la descarga. ACCION: re-subir el archivo al Drive desde el sistema fuente.`);
  }
}

async function _cargarXLSXSeguro(wb, buf, nombreArchivo) {
  try {
    await wb.xlsx.load(buf);
  } catch (e) {
    const msg = String(e?.message || e);
    if (msg.includes('central directory') || msg.includes('Corrupted zip') || msg.includes('invalid signature')) {
      throw new Error(`[XLSX_CORRUPTO] El archivo "${nombreArchivo}" no se pudo abrir (${msg.slice(0, 100)}). Causa: zip corrupto. ACCION: re-subir el archivo al Drive.`);
    }
    throw e;
  }
}
// === FIN VALIDACION ===

// Write banco XLSX (fix formato + separadora salmon): carga el acumulativo original,
// inserta filas nuevas en posicion 2 Y crea una fila separadora salmon (FFFAE2D5)
// inmediatamente despues de las filas nuevas (necesaria para que Script 3 distinga
// lo nuevo del historico).
const ExcelJS = require('exceljs');

const item = $input.first();
if (!item || !item.binary || !item.binary.data) throw new Error('Sin binary del acumulativo original');
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'banco'));

const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('Sin worksheet');

const data = item.json;
const filasNuevas = data.filas_nuevas || [];
const headers = data.headers || [];
const COLOR_SALMON = 'FFFAE2D5';

if (filasNuevas.length === 0) {
  const nCols = ws.columnCount || headers.length || 1;
  let fila2Vacia = true;
  for (let c = 1; c <= nCols; c++) {
    const v = ws.getRow(2).getCell(c).value;
    if (v != null && String(v).trim() !== '') { fila2Vacia = false; break; }
  }
  if (!fila2Vacia) {
    ws.insertRow(2, []);
    for (let c = 1; c <= nCols; c++) {
      ws.getRow(2).getCell(c).fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: COLOR_SALMON }
      };
    }
  }
  const out = await wb.xlsx.writeBuffer();
  const b64 = Buffer.from(out).toString('base64');
  return [{
    json: { ok: true, rowCount: 0, sin_cambios: true, separadora_creada: !fila2Vacia },
    binary: {
      data: {
        data: b64,
        mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        fileName: 'paso2_banco_actualizado.xlsx',
        fileExtension: 'xlsx',
      }
    }
  }];
}

const valoresAInsertar = filasNuevas.map(fila =>
  headers.map(h => fila[h] ?? '')
);

const filaSeparadoraVacia = headers.map(() => null);
const bloqueCompleto = [...valoresAInsertar, filaSeparadoraVacia];

ws.insertRows(2, bloqueCompleto);

const filaSeparadoraIdx = 2 + valoresAInsertar.length;
const nCols = ws.columnCount || headers.length || 1;
for (let c = 1; c <= nCols; c++) {
  ws.getRow(filaSeparadoraIdx).getCell(c).fill = {
    type: 'pattern',
    pattern: 'solid',
    fgColor: { argb: COLOR_SALMON }
  };
}

const out = await wb.xlsx.writeBuffer();
const b64 = Buffer.from(out).toString('base64');

return [{
  json: {
    ok: true,
    rowCount: filasNuevas.length,
    pestanas: wb.worksheets.length,
    separadora_fila: filaSeparadoraIdx,
    color_separadora: COLOR_SALMON,
  },
  binary: {
    data: {
      data: b64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: 'paso2_banco_actualizado.xlsx',
      fileExtension: 'xlsx',
    }
  }
}];
